#include <stdio.h>
#include <string.h> // For strlen
#include <ctype.h>  // For tolower

int main() {
    char line[101]; // Buffer for up to 100 characters + null terminator
    int vowel_count = 0;
    int i;

    // Read a line of text from stdin
    // fgets reads at most sizeof(line)-1 characters, or until a newline.
    // It includes the newline if there's space.
    if (fgets(line, sizeof(line), stdin) == NULL) {
        return 1; // Error reading input
    }

    // Iterate through the string until the null terminator
    // or before the newline character that fgets might have included.
    for (i = 0; line[i] != '\0'; i++) {
        // If fgets included a newline character and it's the last character
        // before the null terminator, we should ignore it for counting.
        if (line[i] == '\n' && line[i+1] == '\0') {
            continue;
        }

        // Convert character to lowercase to handle case-insensitivity
        char ch = tolower(line[i]);

        // Check if the character is a vowel
        if (ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u') {
            vowel_count++;
        }
    }

    // Print the total vowel count
    printf("Total vowels: %d\n", vowel_count);

    return 0;
}
